# ── Config ────────────────────────────────────────────────────────────────────
INTERVAL_S = 3
ROWS        = 10
COLS        = 12
LOGO_B64    = ""

ROW_HOURS  = list(range(10, 20))

def _hour_label(h):
    if h == 12: return "12pm"
    return f"{h}am" if h < 12 else f"{h-12}pm"

ROW_LABELS  = [_hour_label(h) for h in ROW_HOURS]
COL_HEADERS = [f"__:{i*5:02d}-__:{i*5+5:02d}" for i in range(COLS)]

def _empty_grid():
    return [[None] * COLS for _ in range(ROWS)]

def _h12(h):
    if h is None: return "__"
    if h == 0:    return "12"
    return str(h) if h <= 12 else str(h - 12)

def _grid_sum(grid):
    return sum(v for row in grid for v in row if v is not None)


