# ── Server ────────────────────────────────────────────────────────────────────
def server(input, output, session):

    grid_a       = _empty_grid()
    grid_b       = _empty_grid()
    chart_history: deque = deque(maxlen=48)
    fill_counter = [0]
    t0_ever      = [None]

    # ── Reactive timer ────────────────────────────────────────────────────────
    @reactive.calc
    def tick():
        reactive.invalidate_later(INTERVAL_S)
        ts = datetime.now()
        if t0_ever[0] is None:
            t0_ever[0] = ts

        fc  = fill_counter[0]
        idx = fc % (ROWS * COLS)
        r, c = divmod(idx, COLS)

        if fc < 12:      val_a = random.randint(12, 18)
        elif fc < 48:    val_a = random.randint(15, 25)
        else:            val_a = random.randint(10, 21)

        if idx < 2:
            val_b = 0
        else:
            pending = _grid_sum(grid_a) - _grid_sum(grid_b)
            val_b   = min(random.randint(10, 28), max(0, pending))

        grid_a[r][c] = val_a
        grid_b[r][c] = val_b
        fill_counter[0] += 1
        chart_history.append((ts, val_a, val_b))
        return ts

    # ── Grid builder ──────────────────────────────────────────────────────────
    def _build_grid(grid, filled_cls, total_cls):
        last_idx = (fill_counter[0] - 1) % (ROWS * COLS) if fill_counter[0] > 0 else -1
        cur_row, cur_col = divmod(last_idx, COLS) if last_idx >= 0 else (-1, -1)

        cur_h    = ROW_HOURS[cur_row] if cur_row >= 0 else None
        hour_num = _h12(cur_h)
        next_h   = _h12(cur_h + 1) if cur_h is not None else "__"

        ths = [ui.tags.th("Hour", class_="row-hdr-th")]
        for ci, h in enumerate(COL_HEADERS):
            label = f"{hour_num}:55-{next_h}:00" if ci == 11 and cur_h is not None else h.replace("__", hour_num)
            ths.append(ui.tags.th(label))
        ths.append(ui.tags.th("Total", class_="total-th"))

        rows = []
        for r, lbl in enumerate(ROW_LABELS):
            row_vals  = grid[r]
            filled    = [v for v in row_vals if v is not None]
            row_total = sum(filled) if filled else None
            tds = [ui.tags.td(lbl, class_="row-hdr")]
            for c in range(COLS):
                val    = row_vals[c]
                is_cur = (r == cur_row and c == cur_col)
                if val is None:
                    tds.append(ui.tags.td("·", class_="cur-cell" if is_cur else ""))
                else:
                    tds.append(ui.tags.td(str(val), class_=filled_cls + (" cur-cell" if is_cur else "")))
            tds.append(ui.tags.td(
                str(row_total) if row_total is not None else "·",
                class_=total_cls if row_total is not None else "total-empty"
            ))
            rows.append(ui.tags.tr(*tds, class_="cur-row" if r == cur_row else ""))

        colgroup = ui.tags.colgroup(
            ui.tags.col(style="width:4.5%;"),
            *[ui.tags.col(style="width:67px;") for _ in range(COLS + 1)],
        )
        return ui.tags.table(colgroup, ui.tags.thead(ui.tags.tr(*ths)), ui.tags.tbody(*rows), class_="grid-table")

    # ── Outputs ───────────────────────────────────────────────────────────────
    @output
    @render.ui
    def status_bar_ui():
        ts       = tick()
        time_str = ts.strftime("%Y-%m-%d  ") + ts.strftime("%I:%M:%S").lstrip("0")
        last_idx = (fill_counter[0] - 1) % (ROWS * COLS) if fill_counter[0] > 0 else -1
        if last_idx >= 0:
            r, c  = divmod(last_idx, COLS)
            cur_h = ROW_HOURS[r]
            h12   = str(cur_h) if cur_h <= 12 else str(cur_h - 12)
            n12   = str(cur_h + 1) if cur_h + 1 <= 12 else str(cur_h + 1 - 12)
            ampm  = "AM" if cur_h < 12 else "PM"
            slot_str = (f"{h12}:55-{n12}:00 {ampm}" if c == 11
                        else COL_HEADERS[c].replace("__", h12) + " " + ampm)
        else:
            slot_str = "—"
        return ui.div(
            ui.span("UPDATED: ", style="color:#94a3b8;"),
            ui.span(time_str,  style="font-variant-numeric:tabular-nums; display:inline-block; width:18ch; overflow:hidden;"),
            ui.span(" │ CURRENT SLOT: ", style="color:#94a3b8;"),
            ui.span(slot_str, style="font-variant-numeric:tabular-nums; display:inline-block; width:24ch; overflow:hidden;"),
            style=("display:flex; align-items:center; height:1.6rem; min-height:1.6rem; max-height:1.6rem;"
                   "padding:0 .5rem; background:#ffffff; border:1px solid #b8cce4; border-radius:5px;"
                   "font-family:'Space Mono',monospace; font-size:.65rem; color:#2c4a6e;"
                   "white-space:nowrap; overflow:hidden; box-sizing:border-box; flex:0 0 auto;")
        )

    @output
    @render.text
    def latest_a():
        tick()
        last_idx = (fill_counter[0] - 1) % (ROWS * COLS) if fill_counter[0] > 0 else -1
        if last_idx >= 0:
            r, c = divmod(last_idx, COLS)
            v = grid_a[r][c]
            return str(v) if v is not None else "—"
        return "—"

    @output
    @render.text
    def latest_b():
        tick()
        last_idx = (fill_counter[0] - 1) % (ROWS * COLS) if fill_counter[0] > 0 else -1
        if last_idx >= 0:
            r, c = divmod(last_idx, COLS)
            v = grid_b[r][c]
            return str(v) if v is not None else "—"
        return "—"

    @output
    @render.text
    def avg3_a():
        tick()
        pts = [v for _, v, _ in chart_history][-3:]
        return f"{sum(pts)/len(pts):.1f}" if pts else "—"

    @output
    @render.text
    def avg3_b():
        tick()
        pts = [v for _, _, v in chart_history][-3:]
        return f"{sum(pts)/len(pts):.1f}" if pts else "—"

    @output
    @render.ui
    def pending_display():
        tick()
        diff = _grid_sum(grid_a) - _grid_sum(grid_b)
        return ui.div(str(diff) if fill_counter[0] > 0 else "—", class_="stat-value pending")

    @output
    @render.ui
    def sl_total_display():
        tick()
        total = _grid_sum(grid_b)
        return ui.div(str(total) if total > 0 else "—", class_="stat-value sl-total")

    @output
    @render.ui
    def pickup_display():
        tick()
        diff = _grid_sum(grid_a) - _grid_sum(grid_b)
        if fill_counter[0] == 0:
            return ui.div("—", class_="stat-value pickup")
        lo = 15 + math.floor(diff / 20) * 5
        return ui.div(f"{lo} – {lo + 10} min", class_="stat-value pickup")

    @output
    @render.ui
    def table_a():
        tick()
        return _build_grid(grid_a, "filled-a", "total-a")

    @output
    @render.ui
    def table_b():
        tick()
        return _build_grid(grid_b, "filled-b", "total-b")

    @output
    @render.ui
    def src_b_total():
        tick()
        total = _grid_sum(grid_b)
        return ui.div(str(total) if total > 0 else "—", class_="stat-value sl-total")

    @output
    @render.text
    def ab_diff():
        tick()
        return str(_grid_sum(grid_a) - _grid_sum(grid_b)) if fill_counter[0] > 0 else "—"

    @output
    @render.plot(alt="Volume over time")
    def volume_chart():
        tick()

        CA, CB, CT, CG = "#4a90d9", "#229e7e", "#c65327", "#b8cce4"
        total   = fill_counter[0]
        ts_v = a_v = b_v = []
        ref_vals = []

        if chart_history:
            ts_v, a_v, b_v = zip(*chart_history)
            ts_v, a_v, b_v = list(ts_v), list(a_v), list(b_v)
            n = len(ts_v)
            for i in range(n):
                gi = total - n + i
                ref_vals.append(18 if gi < 12 or gi >= 48 else 21)

        n_shown    = len(ts_v)
        first_slot = total - n_shown
        xs         = [(first_slot + i) * INTERVAL_S for i in range(n_shown)]

        page      = 0 if total <= 36 else (total - 37) // 12 + 1
        win_left  = page * 12 * INTERVAL_S - INTERVAL_S * 0.6
        win_right = win_left + INTERVAL_S * 36.2

        fig_w = max(12, 0.55 * 36)
        fig, ax = plt.subplots(figsize=(fig_w, 5.7))
        fig.patch.set_facecolor("#ffffff")
        ax.set_facecolor("#f4f8fd")

        label_kw = dict(ha="center", va="bottom", fontsize=18, fontfamily="monospace",
                        zorder=10, bbox=dict(boxstyle="round,pad=0.1", fc="white", ec="none", alpha=0.7))

        if xs:
            ax.bar(xs, b_v, width=INTERVAL_S * 0.98, color=CB, alpha=0.65, zorder=3, label="SL", align="center")
            if input.show_sl():
                for x, v in zip(xs, b_v):
                    if v > 0: ax.text(x, v + 0.4, str(int(v)), color=CB, **label_kw)

            ax.fill_between(xs, a_v, alpha=.09, color=CA, zorder=1)
            ax.plot(xs, a_v, color=CA, lw=1.8, zorder=4, label="FoH",
                    marker="o", markersize=3.5, markerfacecolor="#ffffff", markeredgewidth=1.3)
            if input.show_foh():
                for x, v in zip(xs, a_v): ax.text(x, v + 0.5, str(int(v)), color=CA, **label_kw)

            ax.plot(xs, ref_vals, color=CT, lw=2, zorder=5, linestyle="--", label="Target", alpha=.9)
            if input.show_tgt():
                for x, v in zip(xs, ref_vals): ax.text(x, v + 0.5, str(int(v)), color=CT, **label_kw)

        ax.set_xlim(win_left, win_right)
        ax.set_ylim(0, 40)
        ax.yaxis.set_major_locator(matplotlib.ticker.MultipleLocator(10))
        ax.yaxis.set_minor_locator(matplotlib.ticker.MultipleLocator(5))

        if xs:
            vis = [(x, ts_v[i]) for i, x in enumerate(xs) if win_left <= x <= win_right]
            if vis:
                vx, vt = zip(*vis)
                ax.set_xticks(list(vx))
                ax.set_xticklabels([t.strftime("%I:%M:%S").lstrip("0") for t in vt],
                                   rotation=20, ha="right", fontsize=6.5,
                                   fontfamily="monospace", color="#2c4a6e")

        plt.setp(ax.get_yticklabels(), color="#2c4a6e", fontsize=7, fontfamily="monospace")
        ax.grid(which="major", color=CG, linewidth=.5, zorder=0)
        ax.grid(which="minor", color=CG, linewidth=.2, alpha=.5, zorder=0)
        for sp in ax.spines.values(): sp.set_edgecolor(CG)
        ax.set_ylabel("Volume", color="#2c4a6e", fontsize=8, fontfamily="monospace")
        ax.legend(loc="upper left", fontsize=8, facecolor="#ffffff",
                  edgecolor=CG, labelcolor="#1e2d45", framealpha=.9, handlelength=1.5)
        fig.tight_layout(pad=.8)
        return fig


# ── App ───────────────────────────────────────────────────────────────────────
app = App(app_ui, server)
